from flask import Flask, request, redirect, url_for, render_template_string, session, flash
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import qrcode
import io
import os
import secrets
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(16))

# Mock database
users_db = {}
sessions_db = {}

# Generate QR code for TOTP
def generate_qr_code(secret, username):
    totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(username, issuer_name="SecureApp")
    qr = qrcode.QRCode(version=1, box_size=10, border=4)
    qr.add_data(totp_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    img_buffer = io.BytesIO()
    img.save(img_buffer)
    img_buffer.seek(0)
    return img_buffer

# Mock user registration
@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        if username in users_db:
            flash('Username already exists')
            return redirect(url_for('register'))
        secret = pyotp.random_base32()
        users_db[username] = {
            'password_hash': generate_password_hash(password),
            'secret': secret
        }
        return redirect(url_for('login'))
    return render_template_string('''
        <form method="post">
            <input type="text" name="username" placeholder="Username" required>
            <input type="password" name="password" placeholder="Password" required>
            <button type="submit">Register</button>
        </form>
    ''')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        user = users_db.get(username)
        if user and check_password_hash(user['password_hash'], password):
            session['user_id'] = username
            session['mfa_verified'] = False
            session['login_time'] = datetime.now().isoformat()
            return redirect(url_for('verify_mfa'))
        flash('Invalid credentials')
    return render_template_string('''
        <form method="post">
            <input type="text" name="username" placeholder="Username" required>
            <input type="password" name="password" placeholder="Password" required>
            <button type="submit">Login</button>
        </form>
    ''')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    
    if session.get('mfa_verified'):
        return redirect(url_for('dashboard'))
    
    username = session['user_id']
    user = users_db.get(username)
    
    if request.method == 'POST':
        otp = request.form['otp']
        totp = pyotp.TOTP(user['secret'])
        if totp.verify(otp, valid_window=2):
            session['mfa_verified'] = True
            return redirect(url_for('dashboard'))
        flash('Invalid OTP')
    
    qr_buffer = generate_qr_code(user['secret'], username)
    qr_data = qr_buffer.getvalue()
    qr_b64 = qr_data.encode('base64').decode('utf-8')
    
    return render_template_string('''
        <h2>Verify MFA</h2>
        <p>Scan the QR code with your authenticator app:</p>
        <img src="data:image/png;base64,{{ qr_b64 }}" alt="QR Code">
        <form method="post">
            <input type="text" name="otp" placeholder="Enter 6-digit OTP" required>
            <button type="submit">Verify</button>
        </form>
    ''', qr_b64=qr_b64)

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session or not session.get('mfa_verified'):
        return redirect(url_for('login'))
    return f'<h2>Welcome {session["user_id"]}</h2><a href="/logout">Logout</a>'

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

# Background MFA verification for improved UX
@app.before_request
def check_mfa():
    if request.endpoint in ['dashboard'] and 'user_id' in session:
        if not session.get('mfa_verified'):
            # Check if session is valid and MFA was verified recently
            login_time = datetime.fromisoformat(session.get('login_time', datetime.now().isoformat()))
            if datetime.now() - login_time > timedelta(minutes=30):
                session.clear()
                return redirect(url_for('login'))
            return redirect(url_for('verify_mfa'))

if __name__ == '__main__':
    app.run(debug=False)